#include <bits/stdc++.h>
using namespace std;
struct Money{
    int m,v;
    double w;
}a[101];
bool cmp(Money a,Money b){
    return a.w>b.w;
}
int n,t;double sum=0.0;
int main(){
    cin>>n>>t;
    for(int i=1;i<=n;i++){
        cin>>a[i].m>>a[i].v;
        a[i].w=double(a[i].v)/double(a[i].m);
    }
    sort(a+1,a+n+1,cmp);
    int i=1;
    while(t>0 && i<=n){
        if(t>=a[i].m){
            t-=a[i].m;
            sum+=a[i].v;
        }
        else{
            sum+=a[i].w*t;
            break;
        }
        i++;
    }
    printf("%.2lf",sum);
    return 0;
}
